var n=".spinning-wheel {\n  width: 20px;\n  height: 20px;\n  box-sizing: border-box;\n  border-radius: 50%;\n  border-top: 2px solid var(--_vn-spinner-bg-color);\n  border-right: 2px solid var(--_vn-spinner-bg-color);\n  border-bottom: 2px solid var(--_vn-spinner-bg-color);\n  border-left: 2px solid var(--_vn-spinner-fg-color);\n  animation: spinningWheelAnimation 2s infinite linear;\n}\n\n@keyframes spinningWheelAnimation {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n";export{n as c};
